from dataclasses import dataclass, field
from datetime import date

@dataclass
class SprintDebtPlan:
    sprint_id: str
    sprint_start: date
    sprint_end: date
    total_points: int
    debt_capacity_points: int    # 20% of total_points

    # P1 items go in first, unconditionally
    p1_items: list[TechDebtRecord] = field(default_factory=list)
    # Remaining debt capacity filled with P2/P3 by context and effort
    scheduled_items: list[TechDebtRecord] = field(default_factory=list)

    def capacity_used(self) -> int:
        all_items = self.p1_items + self.scheduled_items
        # Assumes each debt item is estimated in story points; use 2 as default if not set
        return sum(getattr(r, "estimated_points", 2) for r in all_items)

    def capacity_remaining(self) -> int:
        return max(0, self.debt_capacity_points - self.capacity_used())

    def is_over_capacity(self) -> bool:
        return self.capacity_used() > self.debt_capacity_points

    def sprint_debt_summary(self) -> str:
        lines = [
            f"Sprint {self.sprint_id} debt plan",
            f"Debt capacity: {self.debt_capacity_points} pts / Total: {self.total_points} pts",
            f"Scheduled: {self.capacity_used()} pts ({len(self.p1_items)} P1, {len(self.scheduled_items)} P2/P3)",
        ]
        if self.is_over_capacity():
            lines.append(f"WARNING: over capacity by {self.capacity_used() - self.debt_capacity_points} pts")
        else:
            lines.append(f"Remaining debt capacity: {self.capacity_remaining()} pts")
        return "\n".join(lines)

from dataclasses import dataclass, field
from datetime import date

@dataclass
class PIDebtPlan:
    pi_id: str             # e.g. "PI-2026-Q3"
    pi_start_date: date
    pi_end_date: date
    sprints_in_pi: int     # typically 4–6

    # Committed: must complete by PI end
    committed_p1: list[TechDebtRecord] = field(default_factory=list)
    committed_p2: list[TechDebtRecord] = field(default_factory=list)
    committed_p3: list[TechDebtRecord] = field(default_factory=list)  # stalest only

    # Strategic: require dedicated sprint or architectural investment
    strategic_items: list[TechDebtRecord] = field(default_factory=list)

    # Estimated points available for debt across the PI (sprints × debt_capacity_per_sprint)
    total_debt_capacity_points: int = 0

    def total_committed_items(self) -> int:
        return len(self.committed_p1) + len(self.committed_p2) + len(self.committed_p3)

    def p1_items_cleared_by_end(self) -> bool:
        """
        All P1 items must be committed — they should not carry over to the next PI.
        """
        return all(item in self.committed_p1 for item in self.committed_p1)

    def pi_debt_health(self) -> str:
        issues = []
        if self.committed_p1 and not self.p1_items_cleared_by_end():
            issues.append("P1 items not fully committed for PI — must resolve")
        if not self.committed_p2:
            issues.append("no P2 items committed — P2 debt may carry over indefinitely")
        if self.strategic_items and "architectural debt sprint" not in " ".join(
            getattr(i, "notes", "") for i in self.strategic_items
        ):
            issues.append(f"{len(self.strategic_items)} strategic items need dedicated sprint planning")
        if not issues:
            return "HEALTHY: debt plan complete for PI"
        return "NEEDS REVIEW: " + "; ".join(issues)

from dataclasses import dataclass
from datetime import date

@dataclass
class DebtAllocationMetrics:
    sprint_id: str
    period_start: date
    period_end: date

    # Input metrics
    total_capacity_points: int
    debt_capacity_points: int        # planned allocation
    debt_points_actually_completed: int  # actual debt work done

    # Register health before and after sprint
    high_impact_open_before: int
    high_impact_open_after: int
    total_open_before: int
    total_open_after: int

    # Quality signal
    positive_feedback_rate_before: float
    positive_feedback_rate_end: float

    def allocation_utilisation(self) -> float:
        if self.debt_capacity_points == 0:
            return 0.0
        return self.debt_points_actually_completed / self.debt_capacity_points

    def high_impact_reduction(self) -> int:
        return self.high_impact_open_before - self.high_impact_open_after

    def total_reduction(self) -> int:
        return self.total_open_before - self.total_open_after

    def quality_impact(self) -> float:
        return self.positive_feedback_rate_end - self.positive_feedback_rate_before

    def allocation_effectiveness(self) -> str:
        issues = []
        util = self.allocation_utilisation()
        if util < 0.8:
            issues.append(f"allocation under-utilised ({util:.0%}) — debt items may be too large for sprint slots")
        if util > 1.2:
            issues.append(f"allocation over-run ({util:.0%}) — debt items under-estimated")
        if self.high_impact_reduction() <= 0 and self.high_impact_open_before > 0:
            issues.append("no high-impact debt resolved — review item selection")
        if self.total_reduction() <= 0:
            issues.append("register not shrinking — new debt being created faster than it is resolved")
        if not issues:
            return f"EFFECTIVE: {self.high_impact_reduction()} high-impact items resolved, register reduced by {self.total_reduction()}"
        return "NEEDS REVIEW: " + "; ".join(issues)

from dataclasses import dataclass, field
from datetime import date
from enum import Enum

class DebtDependencyType(str, Enum):
    INTERNAL    = "internal"   # resolved within the team's own codebase
    UPSTREAM    = "upstream"   # requires change from a team this integration depends on
    DOWNSTREAM  = "downstream" # requires change from a team that depends on this integration
    SHARED      = "shared"     # requires change to shared infrastructure (platform team)

@dataclass
class CrossTeamDebtItem:
    debt_record: TechDebtRecord
    dependency_type: DebtDependencyType
    dependent_team: str
    dependency_description: str  # what the other team must do
    pi_committed: bool = False   # whether the other team has committed to the dependency in PI planning

    def can_start_in_sprint(self) -> bool:
        if self.dependency_type == DebtDependencyType.INTERNAL:
            return True
        return self.pi_committed  # can only start if the other team has committed

    def pi_planning_note(self) -> str:
        if self.dependency_type == DebtDependencyType.INTERNAL:
            return "No cross-team dependency."
        status = "COMMITTED" if self.pi_committed else "NOT YET COMMITTED"
        return (
            f"Depends on {self.dependent_team} ({self.dependency_type.value}): "
            f"{self.dependency_description} — {status}"
        )

@dataclass
class PIDebtDependencyPlan:
    pi_id: str
    integration_team: str
    cross_team_items: list[CrossTeamDebtItem] = field(default_factory=list)

    def uncommitted_blockers(self) -> list[CrossTeamDebtItem]:
        return [
            item for item in self.cross_team_items
            if not item.pi_committed and item.debt_record.priority_label() in ("P1", "P2")
        ]

    def pi_readiness_check(self) -> str:
        blockers = self.uncommitted_blockers()
        if blockers:
            teams = set(b.dependent_team for b in blockers)
            return (
                f"PI DEPENDENCY RISK: {len(blockers)} P1/P2 debt items blocked on uncommitted dependencies "
                f"from: {', '.join(teams)}"
            )
        return "DEPENDENCY CLEAR: all P1/P2 cross-team debt dependencies committed for PI"

from dataclasses import dataclass, field
from datetime import date

@dataclass
class DebtAllocationTrend:
    integration_name: str
    sprint_metrics: list[DebtAllocationMetrics] = field(default_factory=list)

    def append(self, metrics: DebtAllocationMetrics) -> None:
        self.sprint_metrics.append(metrics)

    def average_utilisation(self) -> float:
        if not self.sprint_metrics:
            return 0.0
        return sum(m.allocation_utilisation() for m in self.sprint_metrics) / len(self.sprint_metrics)

    def high_impact_trend(self) -> str:
        """
        Is the high-impact debt count generally decreasing over time?
        Compare first half vs second half of tracked sprints.
        """
        if len(self.sprint_metrics) < 4:
            return "insufficient data (need >= 4 sprints)"
        mid = len(self.sprint_metrics) // 2
        first_half_avg = sum(m.high_impact_open_before for m in self.sprint_metrics[:mid]) / mid
        second_half_avg = sum(m.high_impact_open_before for m in self.sprint_metrics[mid:]) / (len(self.sprint_metrics) - mid)
        delta = second_half_avg - first_half_avg
        if delta < -1:
            return f"IMPROVING: high-impact debt decreasing ({delta:.1f} avg change)"
        if delta > 1:
            return f"WORSENING: high-impact debt increasing ({delta:+.1f} avg change)"
        return f"STABLE: high-impact debt flat ({delta:+.1f} avg change)"

    def allocation_volatility(self) -> str:
        if len(self.sprint_metrics) < 3:
            return "insufficient data"
        allocations = [m.allocation_utilisation() for m in self.sprint_metrics]
        avg = sum(allocations) / len(allocations)
        variance = sum((a - avg) ** 2 for a in allocations) / len(allocations)
        std = variance ** 0.5
        if std > 0.25:
            return f"HIGH VOLATILITY: std={std:.2f} — inconsistent debt allocation across sprints"
        return f"STABLE: std={std:.2f} — consistent debt allocation"
